<script lang='ts'>import {onMount} from 'svelte';import AppShell from '$lib/components/AppShell.svelte';import PageHeader from '$lib/components/PageHeader.svelte';import AdminSection from '$lib/components/AdminSection.svelte';import AdminStatCard from '$lib/components/AdminStatCard.svelte';import {currentUser} from '$lib/stores/user';import {fetchAdminGoLiveChecklist, type GoLiveChecklistResponse} from '$lib/api';import GoLiveChecklist from '$lib/components/GoLiveChecklist.svelte';let d:GoLiveChecklistResponse={items:[]};let error='';const load=async()=>{try{d=await fetchAdminGoLiveChecklist();}catch(e:any){error=e.message||'Erreur';}};onMount(load);$: total=d.items.length;$: ok=d.items.filter(i=>i.status==='ok').length;$: warning=d.items.filter(i=>i.status==='warning').length;$: errorCount=d.items.filter(i=>i.status==='error').length;$: manual=d.items.filter(i=>i.status==='manual').length;$: blockingRemaining=d.items.filter(i=>i.blocking&&i.status!=='ok').length;$: optional=d.items.filter(i=>!i.blocking).length;</script>
<AppShell>{#if $currentUser?.role!=='admin'}<p>Accès restreint</p>{:else}<PageHeader title="Go-live checklist" subtitle="Préparation VPS"/><button on:click={load}>Refresh checklist</button><AdminSection title="Summary"><div class="g"><AdminStatCard label="Total items" value={String(total)}/><AdminStatCard label="Items OK" value={String(ok)}/><AdminStatCard label="Items warning" value={String(warning)}/><AdminStatCard label="Items error" value={String(errorCount)}/><AdminStatCard label="Items manual" value={String(manual)}/><AdminStatCard label="Blocking items remaining" value={String(blockingRemaining)}/><AdminStatCard label="Optional items" value={String(optional)}/></div></AdminSection><a href="https://github.com/Alidrix/The_Trend_Scope/blob/main/docs/production.md" target="_blank" rel="noreferrer">docs/production.md</a>{#if error}<p>{error}</p>{/if}<AdminSection title="Checklist"><GoLiveChecklist items={d.items}/></AdminSection>{/if}</AppShell><style>.g{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:.6rem}</style>
